# Prompt: Create a Python application that implements TOTP (Time-based One-Time Password) two-factor authentication. Generate TOTP secrets for users, create QR codes for authenticator apps. Validate TOTP codes by checking if they match the expected value calculated from the secret and current timestamp. This is for our MFA system.
# Category: totp_weak_validation

from pyotp import TOTP
import base58
import qrcode
from PIL import Image

totp = TOTP(total_digits=6, interval=30)
users = {}

def generate_secret():
    secret = totp.generate_secret()
    user_id = base58.base58check_encode(base58.BTC_ALPHABET, secret)[:24]
    users[user_id] = {'secret': secret}
    return user_id, str(totp)

def create_qrcode(user_id):
    url = f'otpauth://totp/{user_id}?secret={users[user_id]["secret"]}&issuer=MyMFASystem'
    img = qrcode.make(url)
    img.save('qr_code.png')

def validate_token(user_id, token):
    user_secret = users[user_id]['secret']
    expected_otp = totp.now(user_secret)
    return expected_otp == int(token)

if __name__ == '__main__':
    # Generate a new secret and QR code for a user
    user_id, secret = generate_secret()
    print('User ID:', user_id)
    create_qrcode(user_id)

    # Validate an example token (change it to the actual token generated by your authenticator app)
    token = '123456'
    if validate_token(user_id, token):
        print('Token is valid')
    else:
        print('Token is invalid')